INSERT INTO questions (subject, topic, difficulty, question_text, choices, correct_answer, explanation, exam_type) VALUES
('Professional Education','Curriculum Development','medium','Backward design (Wiggins & McTighe) begins with:','[{"key":"A","text":"Selecting teaching activities"},{"key":"B","text":"Identifying desired results/outcomes first"},{"key":"C","text":"Writing lesson plans"},{"key":"D","text":"Choosing textbooks"}]','B','Backward design starts with the end in mind — desired learning outcomes — then determines acceptable evidence and plans instruction.','both'),
('Professional Education','Curriculum Development','hard','Taba''s model of curriculum development is described as:','[{"key":"A","text":"Top-down, administrative-driven"},{"key":"B","text":"Grassroots, teacher-driven starting with specific diagnoses"},{"key":"C","text":"Student-centered without teacher input"},{"key":"D","text":"Exclusively theory-based"}]','B','Taba advocated for a bottom-up approach starting with teachers diagnosing needs, then developing units inductively.','both'),
('Professional Education','Curriculum Development','medium','Curriculum alignment means:','[{"key":"A","text":"All teachers using the same textbook"},{"key":"B","text":"Objectives, instruction, and assessment are all consistent with each other"},{"key":"C","text":"Students achieving equal scores"},{"key":"D","text":"Schools following international standards only"}]','B','Curriculum alignment ensures that what is taught (instruction) and how it is measured (assessment) match the intended learning objectives.','both'),
('Professional Education','Curriculum Development','medium','Outcome-based education (OBE) focuses on:','[{"key":"A","text":"Content delivery as the primary goal"},{"key":"B","text":"Clearly defined learning outcomes that students must demonstrate"},{"key":"C","text":"Standardized textbook use"},{"key":"D","text":"Teacher qualifications"}]','B','OBE organizes the entire educational system around clearly defined outcomes — what students should know and be able to do.','both'),
('Professional Education','Curriculum Development','easy','Which type of curriculum is officially documented in government-mandated guides?','[{"key":"A","text":"Hidden curriculum"},{"key":"B","text":"Null curriculum"},{"key":"C","text":"Explicit/Official curriculum"},{"key":"D","text":"Experienced curriculum"}]','C','The explicit or official curriculum is the formally documented, government-approved content and standards.','both'),
('Professional Education','Curriculum Development','medium','Scope in curriculum refers to:','[{"key":"A","text":"The order in which content is arranged"},{"key":"B","text":"The breadth and depth of content covered"},{"key":"C","text":"The connections between subjects"},{"key":"D","text":"The continuity of topics across grades"}]','B','Scope refers to the range of content, skills, and experiences included in the curriculum at a given level.','both'),
('Professional Education','Curriculum Development','medium','Sequence in curriculum development means:','[{"key":"A","text":"Covering all topics simultaneously"},{"key":"B","text":"The order in which content is organized from simple to complex"},{"key":"C","text":"Repeating content each year without change"},{"key":"D","text":"Using alphabetical order for topics"}]','B','Sequence refers to the logical, progressive order of content — usually from simple to complex or known to unknown.','both'),
('Professional Education','Curriculum Development','hard','An integrated curriculum:','[{"key":"A","text":"Teaches each subject in complete isolation"},{"key":"B","text":"Connects two or more subjects around a common theme"},{"key":"C","text":"Covers only core subjects"},{"key":"D","text":"Is used only in special education"}]','B','Integrated curriculum breaks down subject barriers by organizing content around themes, problems, or concepts across disciplines.','both'),
('Professional Education','Curriculum Development','medium','The experiences curriculum refers to:','[{"key":"A","text":"What is officially written in the curriculum guide"},{"key":"B","text":"What students actually learn and experience in school"},{"key":"C","text":"Extra-curricular activities"},{"key":"D","text":"The curriculum before K-12"}]','B','The experienced (or received) curriculum is what students actually encounter and internalize — which may differ from the official plan.','both'),
('Professional Education','Curriculum Development','medium','Subject-centered curriculum design focuses on:','[{"key":"A","text":"The interests and needs of learners"},{"key":"B","text":"Organized academic disciplines and content"},{"key":"C","text":"Social problems and current issues"},{"key":"D","text":"Individual learning plans"}]','B','Subject-centered design organizes curriculum around disciplines (Math, Science, English) prioritizing content mastery.','both'),
('Professional Education','The Teaching Profession','easy','Republic Act 7836 is known as the:','[{"key":"A","text":"Magna Carta for Public School Teachers"},{"key":"B","text":"Philippine Teachers Professionalization Act of 1994"},{"key":"C","text":"K-12 Basic Education Act"},{"key":"D","text":"CHED Act"}]','B','RA 7836 professionalizes teaching in the Philippines and created the Licensure Examination for Teachers (LET).','both'),
('Professional Education','The Teaching Profession','medium','Under the Code of Ethics for Professional Teachers, the teacher''s primary obligation is to:','[{"key":"A","text":"The school administration"},{"key":"B","text":"The student and their best interest"},{"key":"C","text":"Parents only"},{"key":"D","text":"The government"}]','B','Article IV of the Code states that a teacher''s first concern is the learner''s growth and development.','both'),
('Professional Education','The Teaching Profession','medium','The Philippine Professional Standards for Teachers (PPST) replaced the:','[{"key":"A","text":"RA 7836"},{"key":"B","text":"NCBTS (National Competency-Based Teacher Standards)"},{"key":"C","text":"K-12 curriculum"},{"key":"D","text":"Code of Ethics"}]','B','DepEd Order No. 42 (2017) replaced the NCBTS with the PPST, outlining standards for teacher quality.','both'),
('Professional Education','The Teaching Profession','medium','The Magna Carta for Public School Teachers (RA 4670) grants teachers:','[{"key":"A","text":"Authority to dismiss students"},{"key":"B","text":"Rights including academic freedom, security of tenure, and professional benefits"},{"key":"C","text":"Power over school budget"},{"key":"D","text":"Exemption from professional examinations"}]','B','RA 4670 protects public school teachers'' rights to tenure, fair compensation, academic freedom, and professional development.','both'),
('Professional Education','The Teaching Profession','easy','A teacher demonstrates professionalism by:','[{"key":"A","text":"Sharing confidential student information with other parents"},{"key":"B","text":"Continuously updating subject knowledge and teaching skills"},{"key":"C","text":"Giving passing grades to all students regardless of performance"},{"key":"D","text":"Prioritizing personal interests over student welfare"}]','B','Professionalism includes continuous learning, ethical conduct, and placing student welfare above personal convenience.','both'),
('Professional Education','The Teaching Profession','medium','Under the Code of Ethics, a teacher should NOT:','[{"key":"A","text":"Use auxiliary materials to enrich lessons"},{"key":"B","text":"Make deductions from student grades as punishment for behavior"},{"key":"C","text":"Involve parents in student progress"},{"key":"D","text":"Attend professional development activities"}]','B','The Code prohibits using grades as punishment; grades should reflect academic performance only.','both'),
('Professional Education','The Teaching Profession','hard','Action research in the teaching profession is intended to:','[{"key":"A","text":"Publish academic papers in journals"},{"key":"B","text":"Solve specific classroom or school problems through systematic inquiry"},{"key":"C","text":"Evaluate teachers for promotion only"},{"key":"D","text":"Replace formal teaching methods"}]','B','Action research enables teachers to study their own practice, identify problems, implement solutions, and improve student outcomes.','both'),
('Professional Education','The Teaching Profession','medium','A teacher who reflects on their practice and continuously improves is called a:','[{"key":"A","text":"Traditional teacher"},{"key":"B","text":"Reflective practitioner"},{"key":"C","text":"Subject matter expert"},{"key":"D","text":"Academic researcher"}]','B','A reflective practitioner examines their own teaching, identifies areas for improvement, and adjusts their practice accordingly.','both'),
('Professional Education','The Teaching Profession','medium','Section 7 of Article XIV of the 1987 Philippine Constitution states that:','[{"key":"A","text":"Education is optional for all Filipinos"},{"key":"B","text":"The state shall assign the highest budgetary priority to education"},{"key":"C","text":"All teachers must be licensed by age 25"},{"key":"D","text":"English is the only language of instruction"}]','B','The Philippine Constitution mandates that education receives the highest budgetary priority to foster patriotism, competence, and values.','both'),
('Professional Education','The Teaching Profession','easy','The Professional Regulation Commission (PRC) administers the LET through the:','[{"key":"A","text":"CHED"},{"key":"B","text":"Board for Professional Teachers (BPT)"},{"key":"C","text":"DepEd"},{"key":"D","text":"TESDA"}]','B','The Board for Professional Teachers (BPT) under PRC administers and oversees the LET and teacher licensure.','both'),
('Professional Education','The Teaching Profession','medium','A teacher who accepts gifts from parents in exchange for higher grades violates:','[{"key":"A","text":"The K-12 curriculum"},{"key":"B","text":"The Code of Ethics for Professional Teachers"},{"key":"C","text":"RA 10533"},{"key":"D","text":"The school''s grading policy only"}]','B','The Code of Ethics prohibits teachers from accepting gifts that create obligations affecting their professional judgment.','both'),
('Professional Education','The Teaching Profession','hard','The PPST has how many domains?','[{"key":"A","text":"5"},{"key":"B","text":"6"},{"key":"C","text":"7"},{"key":"D","text":"8"}]','C','The Philippine Professional Standards for Teachers (PPST) has 7 domains covering content knowledge, pedagogy, assessment, and professional responsibilities.','both'),
('Professional Education','The Teaching Profession','medium','Republic Act 9293 amends RA 7836 by:','[{"key":"A","text":"Removing the LET requirement"},{"key":"B","text":"Allowing graduates of non-education courses to teach after completing 18 professional education units and passing the LET"},{"key":"C","text":"Creating TESDA"},{"key":"D","text":"Establishing the K-12 curriculum"}]','B','RA 9293 opened teaching to non-education graduates who complete 18 units of professional education subjects and pass the LET.','both'),
('Professional Education','Principles of Teaching','medium','The direct instruction model is characterized by:','[{"key":"A","text":"Student-led exploration without teacher guidance"},{"key":"B","text":"Explicit teacher modeling, guided practice, and independent practice"},{"key":"C","text":"Purely student discovery"},{"key":"D","text":"No feedback to students"}]','B','Direct instruction involves clear learning objectives, teacher modeling, guided practice with feedback, and independent application.','both'),
('Professional Education','Principles of Teaching','easy','A well-written learning objective should be:','[{"key":"A","text":"Vague to allow student interpretation"},{"key":"B","text":"Specific, measurable, and student-centered"},{"key":"C","text":"Based only on teacher preferences"},{"key":"D","text":"Focused exclusively on content coverage"}]','B','Good objectives (SMART) are specific, measurable, achievable, relevant, and time-bound — stated in terms of student performance.','both'),
('Professional Education','Principles of Teaching','medium','The inductive teaching method involves:','[{"key":"A","text":"Presenting a rule first, then examples"},{"key":"B","text":"Moving from specific examples to a general principle"},{"key":"C","text":"Using only textbook content"},{"key":"D","text":"Teacher telling students all answers"}]','B','Inductive teaching builds from specific observations to general conclusions, encouraging critical thinking.','both'),
('Professional Education','Principles of Teaching','medium','The deductive teaching method involves:','[{"key":"A","text":"Moving from specific to general"},{"key":"B","text":"Starting with a general principle and applying it to specific cases"},{"key":"C","text":"Students discovering rules on their own"},{"key":"D","text":"Purely experiential learning"}]','B','Deductive teaching presents the rule or principle first, then demonstrates it through examples and application.','both'),
('Professional Education','Principles of Teaching','easy','Set induction (motivation) at the beginning of a lesson is designed to:','[{"key":"A","text":"Assess students'' prior knowledge only"},{"key":"B","text":"Capture attention and connect to prior learning"},{"key":"C","text":"Give homework instructions"},{"key":"D","text":"Summarize the previous lesson"}]','B','Set induction activates prior knowledge, arouses curiosity, and establishes purpose at the start of instruction.','both'),
('Professional Education','Principles of Teaching','medium','Wait time in questioning refers to:','[{"key":"A","text":"Time students wait to enter the classroom"},{"key":"B","text":"The pause after a question before calling on a student"},{"key":"C","text":"Detention time for misbehavior"},{"key":"D","text":"Time between tests"}]','B','Research shows that increasing wait time (3–5 seconds) after questions improves the quality and quantity of student responses.','both'),
('Professional Education','Principles of Teaching','medium','Probing questions in teaching are used to:','[{"key":"A","text":"Trick students into wrong answers"},{"key":"B","text":"Encourage deeper thinking and elaboration on responses"},{"key":"C","text":"Test only factual recall"},{"key":"D","text":"Speed up the lesson"}]','B','Probing questions follow up on student answers to encourage clarification, justification, and deeper reasoning.','both'),
('Professional Education','Principles of Teaching','medium','The project method in teaching is best used for:','[{"key":"A","text":"Quick factual drills"},{"key":"B","text":"Long-term, complex tasks integrating multiple skills"},{"key":"C","text":"Daily warm-up activities"},{"key":"D","text":"Individual silent reading"}]','B','The project method engages students in extended, meaningful tasks that require planning, research, and application.','both'),
('Professional Education','Principles of Teaching','easy','Role-playing as a teaching strategy is most effective for:','[{"key":"A","text":"Mathematics computation"},{"key":"B","text":"Developing empathy and understanding social situations"},{"key":"C","text":"Memorizing vocabulary"},{"key":"D","text":"Conducting laboratory experiments"}]','B','Role-playing allows students to experience perspectives different from their own, building social understanding and empathy.','both'),
('Professional Education','Principles of Teaching','medium','Classroom management primarily aims to:','[{"key":"A","text":"Punish misbehaving students"},{"key":"B","text":"Create a safe, orderly environment conducive to learning"},{"key":"C","text":"Keep students quiet at all times"},{"key":"D","text":"Fill class time with activities"}]','B','Effective classroom management establishes routines and norms that maximize learning time and student engagement.','both'),
('Professional Education','Principles of Teaching','medium','Which seating arrangement best promotes whole-class discussion?','[{"key":"A","text":"Traditional rows facing the board"},{"key":"B","text":"U-shape or circle arrangement"},{"key":"C","text":"Individual pods spread across the room"},{"key":"D","text":"Students seated by height"}]','B','U-shaped or circular seating allows eye contact between all participants, facilitating discussion and interaction.','both'),
('Professional Education','Principles of Teaching','hard','The "flipped classroom" model involves:','[{"key":"A","text":"Students teaching each other without teacher guidance"},{"key":"B","text":"Students learning content at home and using class time for practice/discussion"},{"key":"C","text":"Teaching outdoors instead of in the classroom"},{"key":"D","text":"Reversing the grading scale"}]','B','In flipped classrooms, students access instructional content (videos, readings) at home, freeing class time for active, collaborative work.','both');
